css:
.print-heading {
    text-align: center;
    margin-bottom: 20px;
}
.print-heading h2 {
    color: #4caf50;
}
.order-details {
    margin-bottom: 20px;
}
.order-details table {
    width: 100%;
}
.order-details td {
    padding: 5px;
}
.items-table {
    width: 100%;
    border-collapse: collapse;
    margin-bottom: 20px;
}
.items-table th, .items-table td {
    border: 1px solid #ddd;
    padding: 8px;
    text-align: left;
}
.items-table th {
    background-color: #4caf50;
    color: white;
}
.totals {
    text-align: right;
    margin-top: 20px;
}
.totals table {
    margin-left: auto;
}
.totals td {
    padding: 5px 10px;
}
